    switch (sym->type) {
      case _URE_ANY_CHAR:
        if ((flags & URE_DOT_MATCHES_SEPARATORS) ||
            !_ure_issep(c))
          matched = 1;
        break;
      case _URE_CHAR:
        if (c == sym->sym.chr)
