        break;
      case _URE_BOL_ANCHOR:
        if (lp == text) {
            sp = lp;
            matched = 1;
        } else if (_ure_issep(c)) {
            if (c == '\r' && sp < ep && *sp == '\n')
              sp++;
            lp = sp;
            matched = 1;
        }
        break;
      case _URE_EOL_ANCHOR:
        if (_ure_issep(c)) {
